sql:
SELECT group_name, group_size
FROM student_groups
WHERE status = 'active';

SELECT COUNT(progress_id) AS "Number of Progress Records"
FROM english_learner_progress
WHERE progress_level = 'A' AND total_hours_of_instruction >= 200;

SELECT group_id, progress_level
FROM english_learner_progress
WHERE intervention_id > 0;

SELECT graduation_rate
FROM graduation_indicators
WHERE group_id = 0 AND indicator_type = 'TS';

